section.code:
{
  "$id": "decimal-as-string-pattern/line-item",
  "type": "object",
  "required": ["sku", "quantity", "unit_price_usd"],
  "additionalProperties": false,
  "properties": {
    "sku": {
      "type": "string",
      "pattern": "^[A-Z0-9-]{2,40}$",
      "description": "Uppercase SKU. Example: 'WIDGET-001'."
    },
    "quantity": {"type": "integer", "minimum": 1, "maximum": 10000},
    "unit_price_usd": {
      "type": "string",
      "pattern": "^\\d+\\.\\d{2}$",
      "description": "USD unit price as decimal string. Two decimals required. Example: '19.99'."
    }
  }
}
